INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('6802805ee3c98b0941765db1', '超级满意的家庭出行选择。选择花园酒店式最正确的啦，粉色仙女小姐姐也温柔又漂亮，semmy小姐姐也超级贴心。
卫生：没得说
环境：赞赞赞
春节出行确实人多，早上早餐瀑布酒店人满了，安排我们去荔湾亭吃早餐，更满意的选择啦，中式自助早餐，更熨帖我们的胃。小朋友也很满意。下次还会继续选择这里，哈哈', '["https://dimg04.c-ctrip.com/images/0235512000ajavn084856_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231312000ajawgar6D26_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-29', '花园双床房', '双床房', '家庭亲子', 145, 0, 10, 8, '["整体满意度","餐饮设施","前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务'),
('6802805ee3c98b0941765db2', '春季来广州，各大五星级酒店价格都让人望而却步，叹为观止，只有花园酒店价格还算亲民??因为分别定的2天，所以房型不一样，客房中心主动帮忙协调???早餐很多人也尽量满足了我打卡的需求??好评??唯一遗憾就是没打卡到米其林餐厅已经约满??', '["https://dimg04.c-ctrip.com/images/0231312000aitwznfFFD0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232o12000aits923801B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232312000aitt9f7C030_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000aitssnq01A5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234s12000aitw6vb3D48_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232z12000aitw8w8ED6E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000aitu6beE7B7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000aituoex2890_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232o12000aittwezE475_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-27', '城央绿意大床房', '大床房', '家庭亲子', 116, 0, 9, 8, '["性价比","客房服务","餐饮设施"]'::jsonb, '性价比', '客房服务', '餐饮设施'),
('6802805ee3c98b0941765db3', '春节期间服务有点跟不上，但是态度都还挺好的，一开始定的房间来不及打扫给安排了公寓房，设施可以说非常老旧，难得的是打扫得很干净没有异味，维护的也不错，后面安排到了我自己定的房间还送了三天的早餐，就很好解决了问题。
广州有很多新的高级酒店，但是广州花园酒店的氛围和底蕴是新的酒店无法比拟的，老市区的大花园的即视感，下午茶也很不错', '["https://dimg04.c-ctrip.com/images/0234i12000anujbew9B20_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232h12000anusl4y2ECD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230v12000anu95wuE6C7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000anuujy2FA6D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234612000antat158A51_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235c12000anu79o8F952_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-13', '红棉大床套房', '套房', '家庭亲子', 162, 0, 10, 9, '["整体满意度","客房服务","卫生状况"]'::jsonb, '整体满意度', '客房服务', '卫生状况'),
('68028068e3c98b0941765db4', '性价比很高的一家酒店，客房和礼宾服务不错。一进门就能闻到香香的味道。不过，前台感觉有点搞不清楚订单情况，我分开预定了2个订单，一个1晚，一个3晚，入住前一天酒店电话我确认了一共2间4晚，办理入住的时候前台说1晚，然后我提醒她有两个订单，才发现是4晚，搞了15分钟吧，当时12点多房间还没打扫出来，我们先外出了，下午2点电话我说可以来拿房卡了，等我4点回来拿房卡，换了个前台，大概又搞不清楚了？又等了5分钟，怎么拿个房卡那么难。。。等第二天游玩回来，进不了房门了，刷不了卡，我猜测真的只做了1晚，但是从头到尾说的都是4晚。吃力。。除此以外其他都挺好的。喜欢酒店内的后花园！', '["https://dimg04.c-ctrip.com/images/0232g12000ak1314h2497_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231u12000ak128qsF587_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235k12000ak1cedk2C1E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-01', '花园大床房', '大床房', '家庭亲子', 285, 0, 27, 8, '["前台服务","退房/入住效率","性价比"]'::jsonb, '前台服务', '退房/入住效率', '性价比'),
('68028068e3c98b0941765db5', '酒店超出预期，真的有大花园，自助早餐晚餐都超级棒，亲子套餐下午还送了点心，小朋友也非常喜欢房间的布置，整体非常用心，总之下次来广州玩还会选择再次入住！唯一的缺点就是入住率太满，人比较多，春节期间明显人手不够～', '["https://dimg04.c-ctrip.com/images/0230m12000aju59mb35CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236d12000aju6nz9BA7B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235d12000aju6mav6EB2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000aju3fu6BA86_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000aju4wlpF198_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235b12000aju6s74A488_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000aju6d4b1C65_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236o12000aju4sm44E06_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000aju4qdc1235_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-02-01', '羊羊得意主题大床房', '主题房', '家庭亲子', 104, 0, 17, 8, '["整体满意度","餐饮设施","房间设施"]'::jsonb, '整体满意度', '餐饮设施', '房间设施'),
('68028068e3c98b0941765db6', '作为有名的老牌酒店，酒店地理位置非常便捷，建筑和景观设计没的说，非常美。只是设施稍显陈旧一点点，虽然看得出是精心设计使用挺便捷，但其实房间小可以不设置浴缸，活动空间会更大。', '["https://dimg04.c-ctrip.com/images/0231512000arc1vikD552_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236w12000arbyt6m022B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-03-10', '花园大床房', '大床房', '情侣出游', 86, 0, 8, 8, '["房间设施","交通便利性","景观/朝向"]'::jsonb, '房间设施', '交通便利性', '景观/朝向'),
('68028068e3c98b0941765db7', '本人在当天下午13时左右到前台拿房，下面这个服务员帮我办理，他说，由于节日房间没打扫卫生，叫我在下午15时到前台找他拿房卡，;我问他说，你来时来到找我就可以了。本人在下午15时到他处，找他拿房卡，他竟然叫我去排队等候，我没排队，叫他找个同事帮我处理，他根本不理我，后来我找到另外一名服务员，拿房不到的原因，是房间没打扫卫生，这样就是酒店的不对了。这就是我们国家的五星级酒店？服务员大冷漠，服务有提升的空间，特别是下面这名服务员。希望携程能了解一下，谢谢。', '["https://dimg04.c-ctrip.com/images/0230q12000aiid5wb836B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232f12000aiigqh969F1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3, 3, '2023-01-26', '城央绿意大床房', '大床房', '情侣出游', 227, 0, 4, 7, '["前台服务","退房/入住效率","整体满意度"]'::jsonb, '前台服务', '退房/入住效率', '整体满意度'),
('68028068e3c98b0941765db8', '年初三带父母来住，年前预订的时候选择了红棉大床房，订前和酒店电话确认过是可以加床的，也在订单的备注里明确要求了。红棉大床有2米宽，我睡加床，父母睡大床，这样父母可以睡的比较舒服。结果在入住前一晚电话告知我有可能无法加床，能否接受换房，我说尽量加床，实在不行换房也是可以的。
到了办理入住的时候前台告诉我床已经不够了，前台给我的选项是1.加钱换粤韵的双床房，现在入住 2.等到四点再入住，到时候电话告知是否有床。如果到时候还是没床就只能三个人住大床房??
粤韵的双床只有1.3米宽，两个成人睡很不舒服。我问前台能不能先保留这间双床房，等到四点能加床就在原房型加床，不能就换到粤韵双床。结果前台告诉我房间是一定不会保留到四点的，到四点也不一定有床可加??
我还能说什么？只能赶紧定下这间双床房。1.3的双床睡两个成人是很不舒服的，晚上父母也并没有睡好。酒店承诺可以加床却无法兑现，也完全没为顾客提供任何解决措施，前台全程冷漠脸，毫无歉意，这就是岭南集团的服务水平？', '["https://dimg04.c-ctrip.com/images/0235412000aisc5nrEC60_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000aisbqc0EBFC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2023-01-27', '红棉大床套房', '套房', '家庭亲子', 430, 4, 3, 9, '["前台服务","房间设施","整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度'),
('68028068e3c98b0941765db9', '临时决定到的广州，提前在网上订了住宿，看到推荐，对花园酒店很感兴趣，定了一间红棉大床房。住宿的前一天就接到酒店电话，询问第二天到店时间，以及同行是否有老人孩子。住宿当天下午一点到的，可能春节期间人多，办理住宿真的很耗费时间，前台的小姐姐们都跟有耐心，就是腾房间的速度真的是有待改进。满分送给酒店里所有服务人员，很贴心，很有耐心。酒店房间可以看到后花园，忘了拍照了。早晨睡了懒觉，在荔湾亭用了自助餐，很不错。下次有机会来广州还会选择住这里。对了，离地铁口也很近，很方便。', '["https://dimg04.c-ctrip.com/images/0230712000aih0mxc1D48_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000aigzz20FB07_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s12000aih0b5v9F4F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-26', '红棉大床套房', '套房', '家庭亲子', 234, 1, 1, 8, '["前台服务","退房/入住效率","交通便利性"]'::jsonb, '前台服务', '退房/入住效率', '交通便利性'),
('68028068e3c98b0941765dba', '服务满意，房间干净，后花园漂亮??', '["https://dimg04.c-ctrip.com/images/0233112000bfohku7822C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-17', '花园大床房', '大床房', '商务出差', 17, 0, 24, 5, '["整体满意度","卫生状况"]'::jsonb, '整体满意度', '卫生状况', NULL),
('68028068e3c98b0941765dbb', '环境很好。 
 瀑布餐厅自助很美味。尤其牛肉粉很正宗。唯一不足是大堂找点热水让孩子喝，就不给。明明有热水器图七。主要是排队办理入住时间太长，所以想讨杯热水，大堂吧的服务员直接冷脸说没有。2099元的消费瞬间觉得不值了。', '["https://dimg04.c-ctrip.com/images/0231512000ai11zgb2981_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000ai0zpxt7706_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234o12000ai10czb4DE1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231k12000ai11ftx45B5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000ai111ws85F9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000ai116ziB847_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234b12000ai12beb60B1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-01-24', '大嘴猴亲子主题大床房', '主题房', '家庭亲子', 109, 2, 1, 8, '["前台服务","餐饮设施","性价比"]'::jsonb, '前台服务', '餐饮设施', '性价比'),
('68028068e3c98b0941765dbc', '2016年第一次带孩子入住留下了非常好的印象，所以2023年带家人来广州依然选择这里。虽然酒店设备老旧了一些，但位置、设施、环境卫生等还是不错的。住了六天唯一非常不开心的是房间的安排！带着老人孩子希望两间房间能稍微近一些，被告知过年人太多只能一个安排在18楼，一个安排在5楼，我仔细看订单我定的应该是18到21楼！而且5楼明显和18楼的房间不一样！可气的是办理的前台小哥是不是觉得北方人好糊弄，给我们的房号1847和524，恨不得把不好的房号和房间都安排给我们，因为比较晚了而且带着老人孩子，大过年的也就没有在争论。不会再去了！', '["https://dimg04.c-ctrip.com/images/0233612000ajcu93hC37E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235a12000ajcusqf389C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-01-29', '花园大床房', '大床房', '家庭亲子', 264, 2, 5, 8, '["前台服务","房间设施","整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度'),
('68028068e3c98b0941765dbd', '交通很便利，酒店旁边吃喝玩乐都齐全。春节带家人入住的，大堂里很热闹，浓郁的岭南风情。逛了一圈，是名副其实的花园酒店，房间很大也整洁。特别夸一夸酒店的服务??，因为临走前想吃一回荔湾亭，经理特意帮我们排号，这一趟旅程非常完美。', '["https://dimg04.c-ctrip.com/images/0230w12000am8ql1h8322_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231m12000am91zhq5337_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230l12000am8qien30A9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-07', '红棉大床套房', '套房', '家庭亲子', 112, 0, 7, 9, '["交通便利性","周边配套","整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度'),
('68028073e3c98b0941765dbe', '金卡会员，办入住的时候说高一级别的房型没房不能升级了，然后我问那加钱可不可以，说可以，然后我就说那既然加钱可以升那说明有空房，有空房为什么不能升房？于是说去确认，回来就说满房了，只剩套房，需要补差价1000多。会员赠送早餐只赠送一份，我说那既然升房没有享受早餐不可以多送一份吗？回答不可以，OK，反正后来也没去过行政酒廊了。房间内只放了两瓶水，第一晚打电话让送水和冰块等了很久都没送，再次打电话之后直到睡觉都没有送来，前后等了差不多有一两个小时……第二天打扫卫生非常敷衍，衣物就这样没有叠好直接塞在枕头中间……孩子小尿尿不小心尿到地上，我们自己简单擦了下，但保洁打扫的时候也没有清理干净，总是能闻到味儿??', '["https://dimg04.c-ctrip.com/images/0236u12000ahysjkc7934_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.2, 2, '2023-01-24', '花园大床房', '大床房', '家庭亲子', 303, 3, 2, 9, '["前台服务","客房服务","卫生状况"]'::jsonb, '前台服务', '客房服务', '卫生状况'),
('68028073e3c98b0941765dbf', '选了好久，最终还是选择了花园酒店，出门右边就是地铁，去哪里都很方便！从进门门童开始，可以感觉到工作人员很热情，进大厅就看见漂亮的装饰树，虽然人多，服务人员很好，总体给人很温馨的感觉，下次有机会去广州还是会选择他们！白金五星级酒店确实是实至名归！', '["https://dimg04.c-ctrip.com/images/0232e12000aiv585w1A10_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000aiv5a91C3AB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s12000aiv5m2d6980_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233012000aiv56vbC9B0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-01-28', '城央绿意大床房', '大床房', '家庭亲子', 122, 0, 5, 8, '["交通便利性","前台服务","整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度'),
('68028073e3c98b0941765dc0', '酒店大堂很大气，服务不错。生意较好前台四个接待火力全开也是要排一会队办入住的，地理位置很不错，5号线淘金地铁站上来就是，对过广州酒家，侧面点都德', '["https://dimg04.c-ctrip.com/images/0232412000aqnbtg9414C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000aqnbvvoD554_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000aqnbrkq2A69_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000aqnbtgn4AB2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000aqnbtzj3459_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-05', '红棉大床套房', '套房', '家庭亲子', 72, 0, 15, 7, '["交通便利性","周边配套","退房/入住效率"]'::jsonb, '交通便利性', '周边配套', '退房/入住效率'),
('68028073e3c98b0941765dc1', '一个改革开放第一批的五星级酒店，历经40年，能保持这样的状况实在难得，各项硬件还是很不错，继续加油！软件方面也很好，这次前台的吴灵伶小姐，漂亮又可爱，关键是服务态度超好，热心主动帮助客人解决问题，工作效率很高，非常熟悉各项流程，让客人感觉很舒服。本人从事服务行业的管理工作数十年，像灵伶这样的员工实在是难得，是企业宝贵的资产。', '["https://dimg04.c-ctrip.com/images/0230812000f1f4dpdACB4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235212000f1f4oin98FB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-07', '花园大床房', '大床房', '其他', 163, 0, 4, 9, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028073e3c98b0941765dc2', '春节广州到处爆满，选择了花园，虽然做好了老酒店的面积是硬伤的准备，但是这家是1.3的床，对带孩子的相对友好，订的是绿意双床。给后面订房的提个醒，1、这个房型的的淋浴必须跨进一个正方形的小浴缸，台阶很高，对小朋友和老人非常不友好。也不安全，不是常规的走入淋浴！！！2.房间不算很旧，但是墙上的插座很多都不好用，床头的那个时钟我住了3天一直7点08！
3.前台的接待办入住也非常的慢！而且没有服务意识和亲和力，一个劲强调需要给他空间！空间！说他墨迹他说嗯，我们是小地方确实慢！广州的是小地方？这是粉刺内含谁呢？
3酒店的瀑布餐厅早餐也不好吃。
4.一楼大堂没有休息区。每次进出酒店大堂都乱哄哄的！
5.周边有广州酒家，利苑，还有其他餐饮选项，如果不赶时间真的不要吃酒店那早餐。。。
6、周边在修地铁去利苑宜安广场需要绕小道步行不远5分钟即可。', '["https://dimg04.c-ctrip.com/images/0231112000aik10ip054E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000aijyuvi4DB0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233n12000aik22mz1FD9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000aik1q4a9DE5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3, 3, '2023-01-26', '城央绿意双床房', '双床房', '家庭亲子', 369, 2, 1, 9, '["房间设施","前台服务","餐饮设施"]'::jsonb, '房间设施', '前台服务', '餐饮设施'),
('68028073e3c98b0941765dc3', '来广州很多次了，第一次入住花园酒店却是因一座有博物馆的酒店，整体感觉非常好。地理位置好，大堂富丽堂皇，干净卫生，早餐丰盛。当然最值得一提是博物馆啦！附照如下！！！', '["https://dimg04.c-ctrip.com/images/0234j12000asxg2s39FC5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d12000asx4jo0F069_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231s12000asxhlua5D17_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231r12000asxhz7mF6EB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000asx4e0u3E46_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236y12000asx5nbf1906_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000asx5j0gF0AB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236312000asx4sgvA93C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-23', '红棉大床套房', '套房', '家庭亲子', 81, 0, 4, 7, '["整体满意度","周边配套","卫生状况"]'::jsonb, '整体满意度', '周边配套', '卫生状况'),
('68028073e3c98b0941765dc4', '天呐花园酒店可以说是我住过服务最好的酒店！国内外也住过很多五星，而且都是国际连锁酒店，但没遇到过比花园服务更好的！！因为我入住时房间有一点异味，前前后后给我打了三次回访电话，第一天就搬来了两台空气净化器，其实在我出去的几个小时里房间已经完全没味道了，酒店还送了我糖和水果。第二天打电话问我是否处理好，还说要送我一个礼物（礼物超级喜欢！谢谢！简直就是猜到我想要什么了），客房服务接电话态度、酒店大堂等工作人员态度都超级好。名副其实宾至如归，以后来广州还住这里！而且位置超级好是我喜欢的老城区，很有老广味道楼下还有很多很多美食。一定会推荐给朋友的', '["https://dimg04.c-ctrip.com/images/0234t12000ai220dkDC7C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230y12000ai221zj927C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231q12000ai23i432D99_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235n12000ai23ei6B1EF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-24', '花园大床房', '大床房', '情侣出游', 271, 0, 3, 9, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('68028073e3c98b0941765dc5', '广州行最后一天（也是除夕这天）入住广州花园
酒店整体新年氛围拉满 各种新春活动

提前两天就有来电确认行程和需求
楼上设置的酒店博物馆 很有情怀（反正很戳我啦）

上榜米其林的早茶-桃园馆 也是很赞 原计划初一这天吃的 没吃成 留点遗憾下次再来', '["https://dimg04.c-ctrip.com/images/0230q12000ahlpols2C3F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000ahlohj2BAEA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000ahlpytp6013_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q12000ahlpm9pC56B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000ahlpzqcC6C3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234512000ahlpcgs3A03_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230i12000ahloxi10C02_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-22', '城央绿意双床房', '双床房', '家庭亲子', 122, 0, 1, 7, '["餐饮设施","整体满意度","前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务'),
('68028073e3c98b0941765dc6', '很庆幸春节期间选择了这家酒店，十足的年味，整个大堂都充满了节日的喜庆，酒店做足了功夫，小朋友们都特别喜欢在大堂里玩，大年初一的早上还在酒店门口和大堂里看到了正宗的舞龙舞狮表演，酒店内部还有一个花园，瀑布，周边吃饭也很便利，点都德和广州酒家步行可达，门口就有地铁，出行也很方便。老牌酒店，精于管理，是不可多得的好选择。', '["https://dimg04.c-ctrip.com/images/0230c12000amkcfsn1D69_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235w12000amkcph3C59A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-08', '城央绿意双床房', '双床房', '朋友出游', 158, 0, 14, 9, '["整体满意度","周边配套","交通便利性"]'::jsonb, '整体满意度', '周边配套', '交通便利性'),
('68028073e3c98b0941765dc7', '元宵节前特意坐高铁从深圳来到广州入住花园酒店。去年10月中旬入住时对酒店的行政酒廊体验很好，所以这次特意选择了可享用行政酒廊的大床房3晚。入住办理、出入开门、行李存放等服务都很到位。大床房内饰、床寝用品、卫生洗浴等设施都令人舒适应手。不巧的是浴室的下水道不很通畅。中午洗澡后流水满地，尽管浴房玻璃门外有地垫，但水还是流到了卫生间和门廊。我们午休1个多小时后积水仍在。如果只住一晚将就一下算了，可是要连住3晚，万一滑倒了周围不是玻璃就是浴缸，地面又是大理石，都不是一件小事，可谓有严重的安全隐患。于是把地面两处的积水拍照后去大堂前台商量能否换一间房。令我想不到的是大堂经理YANNIS范认真耐心听取了我的诉求，留存了我出示的两处积水的照片，很快同意并落实了换房。我们被免费换到了楼层更高，设施更优，面积更大的红棉大床套房。真的被YANNIS范经理的至真至诚的处理结果暖心和感动到了。在此，为她的处理偶发事件的能力、水平和智慧点赞！也为她的果断、魄力和大气格局点赞！再次感谢YANNIS范经理！酒店行政酒廊的早餐、下午茶、欢乐时光的出品、环境、服务一如既往的好。特别点赞早餐。自助+点单、即点即做的模式与上海的J酒店上海中心的早餐模式一样一样，真的令我惊喜和满意。中西式早餐出品比瀑布餐厅的全自助早餐精致优质很多。说实话，行政酒廊的早餐优于自助早餐在酒店行业很少见。我们3天的早餐后面两天都选择了行政酒廊。印度藉服务员CARRIE中文讲得好，服务很主动很勤快很热情很nice。元宵节那天酒店早餐没有汤圆，行政酒廊的欢乐时光也没汤圆，我在向CARRIE询问时随口说了一句：特意来花园酒店过元宵节，没想到在酒店吃汤圆反而成了一种奢望。不一会CARRIE送上来两盅红豆沙芝麻汤圆，真的令我们很惊喜。CARRIE说她和同事把我们的询问和需求反馈到了酒店中餐厅，那里特意为我们做了这两碗汤圆。我和先生听了都非常非常感动。在此，特别感谢中餐厅的后厨师傅，谢谢！辛苦了！也特别感谢印度藉服务员CARRIE，谢谢你的用心和勤快！你们的优质服务让我们度过了一个很美好又难忘的元宵节。细节决定未来，服务决定高度。服务的灵魂是真诚。花园酒店注重细节服务真诚，非常值得入住体验。强烈推荐！', '["https://dimg04.c-ctrip.com/images/0231q12000amss00nCADE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000amsq1lo1FDA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000amssv01BB38_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000amskyf82A52_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230c12000amsxozz6A36_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000amsnuda87C2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000amszxv28641_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000amszxv30716_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233112000amt9c6p9DFD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-09', '花园大床房', '大床房', '情侣出游', 930, 0, 100, 10, '["前台服务","餐饮设施","房间设施"]'::jsonb, '前台服务', '餐饮设施', '房间设施'),
('68028080e3c98b0941765dc8', '春节渡假全家打卡白金五星，连住四晚总体失望，不会再来。房间与快捷酒店同一档次。大堂乱糟糟的有壁画给个四星吧。后花园终于有五星的感觉。春节来也不能要求太高，前厅部与餐饮部很热情。客房部感觉人手不够。礼宾部冷漠，门外的门童直接摆烂，建议调去客房部。对携程铂金没有任何礼遇，春节不差携程这点客流吧。', '["https://dimg04.c-ctrip.com/images/0234g12000aikisn19179_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236i12000aikizb09918_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3, 3, '2023-01-26', '花园双床房', '双床房', '家庭亲子', 146, 0, 5, 8, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('68028080e3c98b0941765dc9', '来之前是先预定的白天鹅，抱着电话咨询下的想法联系了花园酒店，没想到一个电话让我退掉了白天鹅入住花园酒店，事后觉得自己非常英明！从电话预定到入住直到离店，所有的过程都非常完美，哪怕是春节期间细节都做得非常好，从进酒店一刻感受就是宾至如归，清理阿姨态度尤其好，没有评论说的不多给水的事情，只会多给你！总之非常完美，下次还要入住', '["https://dimg04.c-ctrip.com/images/0237012000ai9c6w9DCC1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000ai9d05z5F1C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-25', '红棉大床套房', '套房', '家庭亲子', 161, 0, 28, 8, '["前台服务","整体满意度","客房服务"]'::jsonb, '前台服务', '整体满意度', '客房服务'),
('68028080e3c98b0941765dca', '愉快的入住＆用餐体验，不愧是白金五星级的花园酒店~前台Joyce和Cecilia服务态度好好哦，给的小羊和冰箱贴可可爱爱，无论是check in还是咨询都是亲切又有耐心?? 路上遇到Patrick，指引很到位??总机Dany还有Lydia声音温柔极了，好好听~最后遇到的粉色小姐姐Rain，快捷退房太太太方便啦~', '["https://dimg04.c-ctrip.com/images/0236s12000br43ti530F5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230712000br3wcglBCD0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233b12000br482r44BCA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000br3wxvc3AA1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232o12000br3x6xeAB83_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000br45lb1A5FD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-26', '花园大床房', '大床房', '家庭亲子', 156, 0, 8, 9, '["前台服务","退房/入住效率","整体满意度"]'::jsonb, '前台服务', '退房/入住效率', '整体满意度'),
('68028080e3c98b0941765dcb', '这次出行的惊喜，是花园酒店给的

设施：应该是刚装修不久，整个酒店看起来还很新。能免费停车，酒店的游泳池和健身房的设施也不错

卫生：每天上午打扫很及时。

环境：春节的氛围感简直不能更赞了，大年初一还有舞龙舞狮表演

服务：服务很贴心', '["https://dimg04.c-ctrip.com/images/0234x12000ahlrrpk22C4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000ai15z30831C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g12000ai1424m8C37_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233a12000ai14j3nDA92_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-24', '花园双床房', '双床房', '情侣出游', 118, 0, 16, 7, '["公共设施","客房服务","整体满意度"]'::jsonb, '公共设施', '客房服务', '整体满意度'),
('68028080e3c98b0941765dcc', '老牌五星酒店，花园真的很美。服务人员都很热情，办理入住时TONY MAI 很周到，看到带着小孩，会体贴的送上小饼干，孩子很开心。', '["https://dimg04.c-ctrip.com/images/0232z12000arxfp0aB44A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000arxa4qc7155_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-15', '花园大床房', '大床房', '家庭亲子', 64, 0, 5, 8, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028080e3c98b0941765dcd', '服务非常好，不愧是老牌酒店；春节期间入住，大堂每天都有各种吸引小朋友的表演，最爱小丑表演，对小朋友很有爱；房间有点局促，但是该有的设施都一应俱全，客房服务非常温馨，一点点小建议，退房能否给个快速通道，和入住客人一起排队很慢，中间还有插队办理的，这方面管理有待提高。', '["https://dimg04.c-ctrip.com/images/0230v12000aiozsphBAA5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000aioyo1r6459_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235a12000aioyer91CEA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-27', '花园大床房', '大床房', '家庭亲子', 132, 0, 8, 9, '["前台服务","退房/入住效率","客房服务"]'::jsonb, '前台服务', '退房/入住效率', '客房服务'),
('68028080e3c98b0941765dce', '非常喜欢的', '["https://dimg04.c-ctrip.com/images/0232x12000bm6wvbj7176_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-09', '花园双床房', '双床房', '商务出差', 5, 0, 7, 1, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028080e3c98b0941765dcf', '带爸妈来广州过年，入住花园酒店。第一眼有被酒店大堂惊艳到，背景墙上的红楼梦人物图金碧辉煌，衬着火树银花相当气派且有氛围。我们订了三间房，个人感觉红棉大床房性价比最高，面积也很合理。小套房设计孩子睡觉不会被打扰，二米床适合三口之家。淋浴浴缸都有。虽然设备有些老旧但总体住的还是很舒适的。酒店就在五号线淘金站出口，对面就是友谊商城，广州酒家（有个地道可以过，不用走天桥）。进出非常方便。酒店的服务也很好，工作人员都很热情。是这次很愉快的住宿体验。建议: 换床单被套，和换浴巾可以分开选择。我不需要每天更换床品，但用过的浴巾需要更换一下，但感觉只能全换，或者全不换。马桶间缺一个可以放手机的架子。', '["https://dimg04.c-ctrip.com/images/0233e12000aike4r4A705_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232h12000aikdoi31C99_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000aikejc1A147_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230u12000aikdq7m20F7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-26', '花园双床房', '双床房', '家庭亲子', 295, 0, 3, 9, '["性价比","交通便利性","整体满意度"]'::jsonb, '性价比', '交通便利性', '整体满意度'),
('68028080e3c98b0941765dd0', '花园酒店是老牌的广州五星级酒店，对它还是充满了期待，但入住后发现浴室毯子上明显的一戳头发没有打扫掉，卫生间的边角还有抽屉里都有散落的头发没有打扫干净，对于细节上的处理还是比较失望。酒店的花园是亮点，服务也没啥问题，在酒店荔湾亭吃了中饭感觉也不错值得一去。这次春节假期，酒店在年初一还搞了醒狮活动，非常棒，让我们体验了岭南文化和广州过年热闹的节日气氛。希望酒店能在细节上更完善，毕竟细节才是真正体现酒店的管理和质量！', '["https://dimg04.c-ctrip.com/images/0234i12000aiqey6rAD2D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000aiqgx8lAAC4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236m12000aiqf59573FC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-01-27', '花园大床房', '大床房', '朋友出游', 207, 0, 6, 9, '["卫生状况","整体满意度","餐饮设施"]'::jsonb, '卫生状况', '整体满意度', '餐饮设施'),
('68028080e3c98b0941765dd1', '很意外的收获！特别满意的一次入住，酒店前台的帅哥Billy很客气的帮忙升级了房型，广州历史悠久的大酒店，没有一点陈旧的感觉，干净卫生！这次是晚上入住，一大早就退房了，没来得及体验餐厅的美食和后花园的美景。', '["https://dimg04.c-ctrip.com/images/0230112000apcvhpb6341_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231412000apcv3ms62D6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000apck134BA76_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000apcol2h4AE3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235a12000apcuv0pBA88_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000apctrqj75C1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-23', '花园大床房', '大床房', '独自旅行', 102, 0, 7, 8, '["前台服务","整体满意度","卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况'),
('6802808ae3c98b0941765dd2', '地段不错，出行方便。后花园环境值得观赏。整个酒店服务算中等。不方便的地方有两个，一是停车每次出场均要和礼宾部说，二是作为南方的星级酒店，客房里长供两瓶350ml矿泉水，是不是有点少了，虽然每次找前台要，都能很快送来，是不是可以综合记录下客人需要，以便精准服务，提升体验。', '["https://dimg04.c-ctrip.com/images/0232y12000aiild58E09F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000aiin5cbF3DE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-01-26', '城央绿意双床房', '双床房', '家庭亲子', 135, 0, 4, 8, '["交通便利性","周边配套","前台服务"]'::jsonb, '交通便利性', '周边配套', '前台服务'),
('6802808ae3c98b0941765dd3', '优点：环境好，服务有好有坏吧，整体还不错
缺点：1，设施老化严重，房间内老旧，衣柜换了2房间还是关不严，导致衣柜灯光一直亮很恐怖，总感觉会出来咒怨。2，荔弯亭前台接待，地域歧视，对北方人态度特别差，不仅丑而且说话也不好听，真想骂她。', '["https://dimg04.c-ctrip.com/images/0236612000ahle1br3D57_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.2, 2, '2023-01-22', '花园双床房', '双床房', '家庭亲子', 116, 5, 5, 7, '["房间设施","前台服务","整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度'),
('6802808ae3c98b0941765dd4', '舒适、卫生、方便', '["https://dimg04.c-ctrip.com/images/0230312000bjddxda0B45_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-30', '红棉大床套房', '套房', '家庭亲子', 8, 0, 3, 3, '["整体满意度","卫生状况","交通便利性"]'::jsonb, '整体满意度', '卫生状况', '交通便利性'),
('6802808ae3c98b0941765dd5', '超级满意???? 下次还来??', '["https://dimg04.c-ctrip.com/images/0236l12000bgjhkr96521_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000bgjslhvA086_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236l12000bgjgk234093_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-20', '红棉大床套房', '套房', '家庭亲子', 15, 0, 4, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('6802808ae3c98b0941765dd6', '隔了37年再次入住花园酒店，往事历历在目，感谢花园的花园还在，假山瀑布依旧，看到跑来跑去的孩子们的笑脸，和当年的自己重叠。祝愿酒店历久弥新，带着岁月的庄重和沉淀，永远保持年轻，永远进步。', '["https://dimg04.c-ctrip.com/images/0232s12000aj8cen62283_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000aj8at2079C4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236c12000aj89a9yB220_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231912000aj8etgz6DD5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-29', '花园双床房', '双床房', '家庭亲子', 93, 0, 6, 7, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('6802808ae3c98b0941765dd7', '非常干净，很有岭南文化韵味，可惜时间紧张，有空再来研究，感谢前台KiKi的帮助。', '["https://dimg04.c-ctrip.com/images/0235h12000b8bp0b8757F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232m12000b8bjkc80208_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000b8bo6pcBC85_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-16', '红棉大床套房', '套房', '家庭亲子', 40, 0, 2, 6, '["卫生状况","整体满意度","前台服务"]'::jsonb, '卫生状况', '整体满意度', '前台服务'),
('6802808ae3c98b0941765dd8', '老牌五星酒店是不错的，位置也方便，地铁站出门就是，环境也很好，只是前台办理入住比较慢，另外浴缸是坏的，排水阀有问题不能用，孩子每天玩累了想回来泡一泡澡都不行，住了三天都没给解决，有点扫兴了', '["https://dimg04.c-ctrip.com/images/0235712000aj716fwB31F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230x12000aj75icl5DCD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000aj73oa1A408_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-01-29', '城央绿意大床房', '大床房', '家庭亲子', 94, 0, 7, 8, '["房间设施","前台服务","交通便利性"]'::jsonb, '房间设施', '前台服务', '交通便利性'),
('6802808ae3c98b0941765dd9', '入住花园酒店，真的感觉到老五星的大气高端，金碧辉煌。服务生客气的为您开门问安，感觉宾至如归，很舒服。再去品尝二楼的米其林Stiller，菜品服务都没的说。', '["https://dimg04.c-ctrip.com/images/0233012000aorze0l25DB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231h12000aorzenf0277_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000aorze1d9648_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231d12000aorze1s9872_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000aorzfb5D8F8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233812000aorzi2o928F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000aorzfbk9AB0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w12000aorzhixC049_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235y12000aorzi373A73_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-18', '花园双床房', '双床房', '独自旅行', 77, 0, 46, 8, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('6802808ae3c98b0941765dda', '中秋国庆双节出游，一家三口选择广州花园酒店，连续住了2个晚上，感受超五星服务，感谢前台胡女士给延后退房，入住有送月饼，退房送化妆品！', '["https://dimg04.c-ctrip.com/images/0231112000cagjkk1114F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234i12000caghgxx1851_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000cagnjj456AB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000cagbn7k17B6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000cagj9p0355B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000cagkg2d239B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-30', '花园双床房', '双床房', '家庭亲子', 66, 0, 3, 7, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('6802808ae3c98b0941765ddb', '前厅何小姐服务非常好！酒店环境也很不错，非常适合一家出行居住！', '["https://dimg04.c-ctrip.com/images/0230r12000ekitod46797_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000ekiwalhFC3D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000ekj077k4648_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231g12000ekixn2v90AA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-25', '红棉大床套房', '套房', '情侣出游', 31, 0, 1, 5, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028095e3c98b0941765ddc', '度周末再次选择大羊城 是因为花园酒店
先不说花园酒店是中国唯三的白金五星级饭店 也不说花园酒店是世界知名建筑设计师设计 前国家主席奠基 第二代领导核心题名等这些皇冠 这些光环在我看来 跟大家喜欢的只是奥运冠军 而不是喜欢这个运动本身一样的道理 所以 我不想说
这次我想说一下我对于酒店的个人见解
在传统观念当中 酒店只是我们到另外一个城市需要晚上住宿的地方 随着我的出行越来越多 具有精准定位 独立设计 独具匠心 具有内涵 体验美好的酒店也慢慢成为了我的目的地之一
这些酒店所散发出来的吸引力不仅仅是一种对于酒店或者旅行的情怀 更多的是渗透于生活当中的延绵沉淀 现在已经慢慢成为我的一种生活方式 简单点说 就是吃美食 耍酒店
关于花园酒店建筑本身的一点思考
花园酒店是贝聿铭先森指导的 贝先森是美国宾夕法尼亚大学建筑学毕业 作为华人的贝先森在中国有很高的知名度 我见过贝先森的作品 例如香港????中银大厦 但我还没去过法国巴黎卢浮宫 花园酒店在差不多四十年前就建造完成 今天仍然洋气 理念仍然先进 细节仍然到位 在其作品中体现得淋漓尽致 其实本质就是更早的接触了现代文明', '["https://dimg04.c-ctrip.com/images/0232c12000ajqlic1EA88_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w12000ajqnhct9566_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234g12000ajqllq10666_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-31', '粤韵大床套房', '套房', '家庭亲子', 486, 0, 38, 9, '["整体满意度","房间设施","公共设施"]'::jsonb, '整体满意度', '房间设施', '公共设施'),
('68028095e3c98b0941765ddd', '很好的一次入住体验 凌晨的时候入住工作人员还是很热情很细心，房间的环境设施都很满意，床对于我来说有点软但是朋友觉得很舒服很满意。
就是地下停车场不大好找绕了两圈进去问了工作人员才知道在哪 然后早上忘记要停车券 想想算了付了50停车费 btw整体五分确实值得', '["https://dimg04.c-ctrip.com/images/0235012000ag1z11p3209_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234d12000ag1zysd7071_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236r12000ag20txxB308_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-15', '花园大床房', '大床房', '其他', 128, 0, 17, 7, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68028095e3c98b0941765dde', '老牌的五星级酒店，设施有些年头了，办入住给免费升级了套房。还免费加了一个床。马桶声音有点大，卫生有带提高。酒店的床垫是很舒服值得入睡的，在携程定的双早，到行政酒廊用早餐说服务员说只有一位，瞬间心情就不太好，最后沟通还是去吃了早餐的，早餐种类较少，味道还可以。水果nice、尤其是蓝莓很好??。不明白酒店内部的各个部门有什么问题没有沟通好。原本还打算周六继续订房住的。现在还在还在纠结中….', '["https://dimg04.c-ctrip.com/images/0206m12000aff3juoE325_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0203512000aff2yln7117_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0203a12000aff3n8b12F5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-01-12', '花园双床房', '双床房', '商务出差', 194, 1, 61, 7, '["房间设施","餐饮设施","整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度'),
('68028095e3c98b0941765ddf', '刚入住时候没有强调自己的明确需求、被前台安排了边边房，很是生气??立马下楼联系经理换房??定了双床后台却显示大床，搞了乌龙，只能再换一次，最后由于他们的失误让我耽误了那么久才入住，免费给我升级了大房双床！很是喜欢！舒服！自助餐品种确实不多、但能吃饱，要求不高哈哈哈，里面的花园真的绝了！满满绿植～设计的好赞！', '["https://dimg04.c-ctrip.com/images/0206712000afe83rq65D6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0204l12000afea0vo096B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0205912000afebd2f3364_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0206g12000afeao825DC7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-12', '花园双床房', '双床房', '朋友出游', 154, 0, 3, 8, '["前台服务","退房/入住效率","整体满意度"]'::jsonb, '前台服务', '退房/入住效率', '整体满意度'),
('68028095e3c98b0941765de0', '评分真的很水，最多就是个快捷酒店的样子，跟五星一点也不沾边，卫生太差，尤其是马桶，层高和低，很压抑，装修老旧，瀑布餐厅的早餐纯属噱头，种类少且难吃，并且也没有什么景观，踩雷', '["https://dimg04.c-ctrip.com/images/0232a12000ajs8eis5ECF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000ajs8b5jD266_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000ajs6v0t1D94_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235912000ajs4lbb1E58_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235212000ajs66i11296_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2, 2, '2023-01-31', '花园大床房', '大床房', '家庭亲子', 86, 2, 8, 8, '["卫生状况","房间设施","整体满意度"]'::jsonb, '卫生状况', '房间设施', '整体满意度'),
('68028095e3c98b0941765de1', '房间不大，设备旧了，但保养很好，服务在线！其酒店的餐厅更是顶流！下次去广州还回去！', '["https://dimg04.c-ctrip.com/images/0234212000aynu6ry7392_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233r12000aynwdzdB05C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236112000aynskv6965B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000aynuabtB701_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235v12000aynu9i8C7D2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234y12000aynu6s00E88_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236012000aynt9ysABDC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232j12000ayo7eol5300_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236512000aynok095CF5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-04-15', '花园双床房', '双床房', '商务出差', 41, 0, 2, 7, '["房间设施","餐饮设施","整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度'),
('68028095e3c98b0941765de2', '前台大堂的员工都给人一种宾至如归的感觉，特别是前台带人办理入住的粉色衣服的几个小姐姐们超有礼貌的。
服务一流的花园酒店，基本上想要什么都可以商量着来。
设施都是新的，酒店装修复古，但住下却有家的感觉，很喜欢。', '["https://dimg04.c-ctrip.com/images/0231s12000agu7mhsAB7E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000agu4jzbDD14_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232v12000agu3znj05C5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-19', '花园大床房', '大床房', '情侣出游', 104, 0, 4, 8, '["前台服务","整体满意度","房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施')
